public function getOcfilterFaq($page_id) {
	$faq = [];
	$type = 'ocfilter';
	$query = $this->db->query("SELECT * FROM " . DB_PREFIX . "seo_faq WHERE category_id = '" . (int)$page_id . "' AND type = '" . $type . "' ORDER BY sort_order ASC");
	foreach ($query->rows as $row) {
		$faq_data = [];
		$description_query = $this->db->query("SELECT * FROM " . DB_PREFIX . "seo_faq_description WHERE faq_id = '" . (int)$row['faq_id'] . "'");
			foreach ($description_query->rows as $result) {
				$faq_data[$result['language_id']] = [
					'question' => $result['question'],
					'answer' => $result['answer']
				];
			}
		$faq[] = [ 
			'sort_order' => $row['sort_order'],
			'data' => $row,
			'faq_data' => $faq_data
		];	
	}
	return $faq;
}

