			$this->db->query("INSERT INTO " . DB_PREFIX . "seo_faq_description SET faq_id = '" . (int)$faq_id . "', category_id = '" . (int)$blogcategory_id . "', language_id = '" . (int)$language_id . "', question = '" . $this->db->escape($value['question']) . "', answer = '" . $this->db->escape($value['answer']) . "', type = 'oct_blog_category'");
		}
	}
}

